async function apiFetch(url, opts = {}, noThrow = false) {
  // Passa URL COMPLETA como _target вҖ” proxy repassa sem modificar
  function buildProxyUrl(originalUrl) {
    const proxyBase = getProxyBase();
    if (proxyBase) return proxyBase + '/proxy?_target=' + encodeURIComponent(originalUrl);
    if (location && location.port === '8080') return '/proxy?_target=' + encodeURIComponent(originalUrl);
    if (location && location.protocol === 'file:') return DEFAULT_PROXY_BASE + '/proxy?_target=' + encodeURIComponent(originalUrl);
    return '';
  }
  const exchangeHosts = ['api.binance.com', 'api.mexc.com', 'api.kucoin.com', 'api.gateio.ws', 'open-api.bingx.com', 'api.bybit.com', 'www.okx.com'];
  const isExchangeUrl = exchangeHosts.some(h => url.includes(h));
  const forceProxy = isExchangeUrl;
  let lastErr = null;

  // 1) Tenta proxy (render/local)
  try {
    const proxyUrl = buildProxyUrl(url);
    if (!proxyUrl) {
      lastErr = 'Proxy nГЈo configurado. Use ?proxy=URL_DO_BACKEND ou defina localStorage.proxy_base';
    } else {
      const h = { ...(opts.headers || {}) };
      delete h['content-length']; delete h['Content-Length'];
      const r = await fetch(proxyUrl, { ...opts, headers: h, signal: AbortSignal.timeout(10000) });
      if (r.ok || r.status < 500) return r;
    }
  } catch (e) {
    console.warn('Proxy falhou:', e.message);
    lastErr = e.message || 'Proxy offline';
    const led = document.getElementById('proxy-led');
    if (led) led.style.background = 'var(--red)';
  }

  // 2) Tenta direto (apenas quando nГЈo for exchange/CORS)
  if (!forceProxy) {
    try {
      const r = await fetch(url, { ...opts, signal: AbortSignal.timeout(8000) });
      return r;
    } catch (e) {
      console.warn('Direto falhou:', e.message);
    }
  }

  // 3) Fallback: corsproxy.io (apenas GET pГәblico)
  if (!opts.method || opts.method === 'GET') {
    try {
      const r = await fetch('https://corsproxy.io/?' + encodeURIComponent(url), { signal: AbortSignal.timeout(8000) });
      if (r.ok) return r;
    } catch (e) { }
  }

  if (!noThrow) throw new Error(lastErr || 'Proxy local offline. Inicie o backend Java: java -jar arb-hft-engine-1.0.0.jar');
}
